  ('heelevel3-7ec62a85-moex-00003', 'heelevel3-7ec62a85', 'heelevel3-7ec62a85-moex-114-de0a21a2', 'sub-heelevel3-7ec62a85-01', NULL, 'essay', '毒販A在臺灣將毒品以國際包裹寄送到日本，當地日本人B為收件人。
因日本海關發現包裹有毒品，通知日本警方後，B被日本警方逮捕偵辦。
日本警方有製作 B 之筆錄，B 的陳述內容不利於 A。日本警方將犯罪情
資通知我國，經我國檢察官對 A 提起公訴，指控其運輸毒品。法院以日
本與我國無司法互助約定，而且B在日本，難以預期B會到我國法庭應
訊，遂僅宣讀B的日本警察筆錄，請A表示意見後，即採為A運輸毒品
罪之主要證據。A主張法院判決違法，請分析其主張有無理由。（35分）', '[]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:33:20+00:00", "source_pdf_sha1": "3f807377b1b5", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "114080", "c": "229", "s": "0915", "q": "1"}, "raw_section_label": "甲、申論題部分", "subject": "刑法與刑事訴訟法", "year": "114", "exam_name": "114年公務人員高等考試三級考試暨普通考試", "original_question_number": "三", "answer_corrected": false, "flags": [], "civil_slug": "heelevel3", "civil_category": "法律廉政"}'::jsonb, NULL),
